import React from 'react';
import { motion } from 'framer-motion';

interface FloatingNodeProps {
  type: 'cube' | 'cross' | 'dot';
  position: { top: string; left: string };
  size: number;
  depth: 'far' | 'mid' | 'near'; // for depth of field blur
  delay: number;
  duration: number;
  color: string;
}

const FloatingNode: React.FC<FloatingNodeProps> = ({
  type,
  position,
  size,
  depth,
  delay,
  duration,
  color,
}) => {
  // Blur intensity based on depth
  const blurAmount = depth === 'far' ? 8 : depth === 'mid' ? 4 : 0;
  const opacity = depth === 'far' ? 0.15 : depth === 'mid' ? 0.35 : 0.5;

  // Floating animation - infinite sine wave on y-axis
  const floatingVariants = {
    animate: {
      y: [0, -30, 0],
      transition: {
        duration,
        repeat: Infinity,
        ease: 'easeInOut',
        delay,
      },
    },
  };

  // Render different node types
  const renderNode = () => {
    switch (type) {
      case 'cube':
        // Wireframe cube representation
        return (
          <svg width={size} height={size} viewBox="0 0 100 100" fill="none">
            {/* Front face */}
            <rect x="20" y="20" width="60" height="60" stroke={color} strokeWidth="2" />
            {/* Back face (offset) */}
            <rect x="30" y="10" width="60" height="60" stroke={color} strokeWidth="1.5" opacity="0.6" />
            {/* Connection lines */}
            <line x1="20" y1="20" x2="30" y2="10" stroke={color} strokeWidth="1.5" opacity="0.6" />
            <line x1="80" y1="20" x2="90" y2="10" stroke={color} strokeWidth="1.5" opacity="0.6" />
            <line x1="20" y1="80" x2="30" y2="70" stroke={color} strokeWidth="1.5" opacity="0.6" />
            <line x1="80" y1="80" x2="90" y2="70" stroke={color} strokeWidth="1.5" opacity="0.6" />
          </svg>
        );
      case 'cross':
        // 3D coordinate cross
        return (
          <svg width={size} height={size} viewBox="0 0 100 100" fill="none">
            <line x1="50" y1="0" x2="50" y2="100" stroke={color} strokeWidth="2" />
            <line x1="0" y1="50" x2="100" y2="50" stroke={color} strokeWidth="2" />
            <circle cx="50" cy="50" r="8" stroke={color} strokeWidth="2" />
            {/* Depth indicator lines */}
            <line x1="50" y1="50" x2="70" y2="30" stroke={color} strokeWidth="1.5" opacity="0.6" />
            <line x1="50" y1="50" x2="30" y2="70" stroke={color} strokeWidth="1.5" opacity="0.6" />
          </svg>
        );
      case 'dot':
        // Simple dot with glow
        return (
          <div
            className="rounded-full"
            style={{
              width: size,
              height: size,
              backgroundColor: color,
              boxShadow: `0 0 ${size * 0.5}px ${color}80, 0 0 ${size}px ${color}40`,
            }}
          />
        );
      default:
        return null;
    }
  };

  return (
    <motion.div
      className="absolute"
      style={{
        top: position.top,
        left: position.left,
        filter: `blur(${blurAmount}px)`,
        opacity,
      }}
      variants={floatingVariants}
      animate="animate"
    >
      {renderNode()}
    </motion.div>
  );
};

export default FloatingNode;
